function countWords(text: string): number {
  return text.trim().split(/\s+/).filter(Boolean).length;
}

export const WORKOUT_KNOWLEDGE_BASE_WORD_COUNT = countWords(RAW_WORKOUT_KNOWLEDGE_BASE);

function parseSection(block: string): KnowledgeBaseSection | null {
  const trimmed = block.trim();
  if (!trimmed) return null;

  const lines = trimmed.split('\n');
  const title = lines[0]?.trim() ?? '';
  const keywordsLine = lines.find((line) => line.startsWith('Keywords:'));
  const keywords = keywordsLine
    ? keywordsLine.replace('Keywords:', '').split(',').map((value) => value.trim().toLowerCase()).filter(Boolean)
    : [];

  const contentStartIndex = lines.findIndex((line) => line.startsWith('Summary:'));
  const content = contentStartIndex === -1
    ? lines.slice(1).join('\n').trim()
    : lines.slice(contentStartIndex).join('\n').trim();

  if (!title || !content) return null;

  return { title, keywords, content };
}

export function parseWorkoutKnowledgeBase(raw: string): KnowledgeBaseSection[] {
  return raw
    .split('\n## ')
    .map((block, index) => (index === 0 ? block.replace(/^#.*\n?/g, '') : block))
    .map(parseSection)
    .filter((section): section is KnowledgeBaseSection => section !== null);
}

export const WORKOUT_KNOWLEDGE_SECTIONS = parseWorkoutKnowledgeBase(RAW_WORKOUT_KNOWLEDGE_BASE);
